export interface WorkerSourceOptions {
  readonly configModule: string;
}

export function generateWorkerSource({
  configModule,
}: WorkerSourceOptions): string {
  const lines = [
    "// Generated by plumix — do not edit.",
    "// Regenerated from plumix.config.ts on each build.",
    "",
    'import { buildApp } from "plumix";',
    `import config from ${JSON.stringify(configModule)};`,
    "",
    "const appPromise = buildApp(config);",
    "let handler;",
    "",
    "export default {",
    "  async fetch(request, env, ctx) {",
    "    const app = await appPromise;",
    "    handler ??= config.runtime.buildFetchHandler(app);",
    "    return handler(request, env, ctx);",
    "  },",
    "};",
    "",
  ];
  return lines.join("\n");
}
